parameters.inputSchema:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "title": "Job Match & Tailored Resume Output",
  "type": "object",
  "required": ["relevancy", "score", "justification"],
  "properties": {
    "relevancy": {
      "type": "boolean",
      "description": "True if candidate suitability score >= 50%, else False"
    },
    "score": {
      "type": "string",
      "pattern": "^(100|[1-9][0-9]?|0)%$",
      "description": "Percentage string from 0% to 100% without leading zeros"
    },
    "justification": {
      "type": "array",
      "minItems": 1,
      "maxItems": 10,
      "items": {
        "type": "string",
        "minLength": 5,
        "description": "Short bullet point reasoning for relevancy"
      }
    }
  },
  "additionalProperties": false
}

