=Here is the job description and my current resume. Evaluate alignment and generate output as defined in the System Prompt. I prefer 7-8 points on firts experience and 3-4 on second.

### Job Description:
{{ $('Set Job Details').first().json.job_description }}

### My Resume:
{{ $('Set Global Vars').first().json.resume }}

parameters.jsCode:
const tailoredResume = $input.first().json.output;
const originalResume = typeof $("Set Global Vars").first().json.resume === 'string' 
  ? JSON.parse($("Set Global Vars").first().json.resume) 
  : $("Set Global Vars").first().json.resume;

function deepMerge(target, source) {
  for (const key in source) {
    if (source[key] && typeof source[key] === 'object' && !Array.isArray(source[key])) {
      if (!target[key] || typeof target[key] !== 'object') {
        target[key] = source[key];
      } else {
        deepMerge(target[key], source[key]);
      }
    } else if (target[key] === undefined || target[key] === null || target[key] === '') {
      target[key] = source[key];
    }
  }
  return target;
}

const mergedResume = deepMerge(tailoredResume, originalResume);
return mergedResume;
